{
  "edits": [
    {
      "newText": "}

// ─── Improvement Persistence Tests ───

{
  // Create improvement on a user_acceptance task, verify persistence
  const cwd = mkdtempSync(join(tmpdir(), "ypi-studio-improvement-create-"));
  try {
    const contextId = "pi_imp_create";
    const task = createYpiStudioTask({ cwd, title: "Improvement test", workflowId: "feature-dev", contextId });
    // Move task to user_acceptance
    transitionYpiStudioTask(task.id, { cwd, to: "planning", override: true, contextId });
    updateYpiStudioImplementationPlan(task.id, {
      cwd,
      action: "update_implementation_plan",
      contextId,
      implementationPlan: {
        schemaVersion: 2,
        subtasks: [{ id: "A", title: "A", order: 10, dependsOn: [] }],
      },
    });
    writePlanReview(cwd, task.id, contextId);
    transitionYpiStudioTask(task.id, { cwd, to: "awaiting_approval", override: true, contextId });
    recordYpiStudioUserApproval(cwd, contextId, "确认开始实现");
    transitionYpiStudioTask(task.id, { cwd, to: "implementing", override: true, contextId });
    transitionYpiStudioTask(task.id, { cwd, to: "checking", override: true, contextId });
    transitionYpiStudioTask(task.id, { cwd, to: "review", override: true, contextId });
    transitionYpiStudioTask(task.id, { cwd, to: "user_acceptance", override: true, contextId });
    assert.equal(task.status === "user_acceptance" ? "user_acceptance" : (getYpiStudioTaskDetail(cwd, task.id)?.status), "user_acceptance");

    // Create first improvement
    const withImp1 = createYpiStudioImprovement(task.id, {
      cwd,
      action: "create_improvement",
      title: "Fix narrow layout",
      feedback: "The sidebar is too narrow on mobile.",
      contextId,
    });
    assert.equal(withImp1.status, "waiting_for_improvements");
    assert.equal(withImp1.improvements?.parentStatus, "waiting_for_improvements");
    assert.equal(withImp1.improvements?.instances.length, 1);
    assert.equal(withImp1.improvements?.instances[0].displayId, "IMP-001");
    assert.equal(withImp1.improvements?.instances[0].status, "analysis");
    assert.equal(withImp1.improvements?.instances[0].owner, "improver");
    assert.equal(withImp1.improvements?.instances[0].title, "Fix narrow layout");
    assert.equal(withImp1.improvements?.instances[0].feedback, "The sidebar is too narrow on mobile.");
    assert.ok(withImp1.improvements?.instances[0].id.startsWith("imp_"));

    // Create second improvement
    const withImp2 = createYpiStudioImprovement(task.id, {
      cwd,
      action: "create_improvement",
      title: "Add loading state",
      feedback: "No loading indicator while fetching.",
      contextId,
    });
    assert.equal(withImp2.improvements?.instances.length, 2);
    assert.equal(withImp2.improvements?.instances[1].displayId, "IMP-002");
    assert.equal(withImp2.improvements?.parentStatus, "waiting_for_improvements");

    // Verify improvements are persisted (re-read task)
    const reloaded = getYpiStudioTaskDetail(cwd, task.id);
    assert.equal(reloaded?.improvements?.instances.length, 2);
    assert.equal(reloaded?.improvements?.instances[0].displayId, "IMP-001");
    assert.equal(reloaded?.improvements?.instances[1].displayId, "IMP-002");

    // Verify instances do NOT appear as top-level tasks
    const allTasks = [...Array.from({ length: 0 })];
    // Just verify the task directory doesn't create new top-level task entries
    const detail = getYpiStudioTaskDetail(cwd, task.id);
    assert.ok(detail);
    assert.equal(detail.improvements?.instances.length, 2);
    // The improvements directory exists inside the task directory
    assert.ok(existsSync(join(cwd, ".ypi", "tasks", task.id, "improvements")));
    assert.ok(existsSync(join(cwd, ".ypi", "tasks", task.id, "improvements", withImp1.improvements?.instances[0].id)));
    assert.ok(existsSync(join(cwd, ".ypi", "tasks", task.id, "improvements", withImp1.improvements?.instances[0].id, "brief.md")));
  } finally {
    rmSync(cwd, { recursive: true, force: true });
  }
}

